// src/main.ts
import '@ios-web-bluetooth/core';
import { bootstrapApplication } from '@angular/platform-browser';
import { AppComponent } from './app/app.component';
bootstrapApplication(AppComponent);

// heart-rate.component.ts
import { Component, NgZone, signal } from '@angular/core';
@Component({
  standalone: true,
  selector: 'app-heart-rate',
  template: `<button (click)="connect()">Connect</button><p>{{ bpm() ?? '—' }} bpm</p>`
})
export class HeartRateComponent {
  bpm = signal<number | null>(null);
  constructor(private zone: NgZone) {}
  async connect() {
    const device = await navigator.bluetooth.requestDevice({
      filters: [{ services: ['heart_rate'] }]
    });
    const server = await device.gatt!.connect();
    const service = await server.getPrimaryService('heart_rate');
    const char = await service.getCharacteristic('heart_rate_measurement');
    await char.startNotifications();
    char.addEventListener('characteristicvaluechanged', (ev) => {
      const v = (ev.target as BluetoothRemoteGATTCharacteristic).value!;
      this.zone.run(() => this.bpm.set(v.getUint8(0) & 0x01 ? v.getUint16(1, true) : v.getUint8(1)));
    });
  }
}

